    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    vector<int> result;
    for(int i = 0; i < n; i++) if(nums[i] != 0) result.push_back(nums[i]);
    for(int i = 0; i < n; i++) if(nums[i] == 0) result.push_back(nums[i]);
    for(int i = 0; i < n; i++) cout << result[i] << ' ';
